+proptest! {
+    #![proptest_config(ProptestConfig::with_cases(30))]
+
+    /// Excel round-trip preserves DataFrame shape.
+    #[test]
+    fn prop_excel_round_trip_preserves_shape(df in arb_int64_dataframe(8, 4)) {
